mapper.select:
SELECT mst.usrnme as userName, userinfo.usreml as email, mst.usrpsd as password FROM shield_auth.shdldgmst mst JOIN shield_auth.shdusrrgst userinfo ON mst.ldguid = userinfo.ldguid WHERE mst.usraccsts = 'ACTIVE'
AND mst.usrnme = #{filter.userName}
AND userinfo.usreml = #{filter.userEmail}
